import {
  IOResult,
  ResourceName,
  command,
  gunzip,
  materialize,
  readStdinAsync,
  specOf,
  type ByteSource,
  type CommandFnResult,
  type CommandOpts,
  type PathSpec,
} from '@struktoai/mirage-core'
import { stream as redisStream } from '../../../core/redis/stream.ts'
import type { RedisAccessor } from '../../../accessor/redis.ts'

const ENC = new TextEncoder()

async function zcatCommand(
  accessor: RedisAccessor,
  paths: PathSpec[],
  texts: string[],
  opts: CommandOpts,
): Promise<CommandFnResult> {
  let raw: Uint8Array
  if (paths.length > 0 && paths[0] !== undefined) {
    raw = await materialize(redisStream(accessor, paths[0]))
  } else {
    const stdinBytes = await readStdinAsync(opts.stdin)
    if (stdinBytes === null) {
      return [null, new IOResult({ exitCode: 1, stderr: ENC.encode('zcat: missing input\n') })]
    }
    raw = stdinBytes
  }
  const out = await gunzip(raw)
  const result: ByteSource = out
  return [result, new IOResult()]
}

export const REDIS_ZCAT = command({
  name: 'zcat',
  resource: ResourceName.REDIS,
  spec: specOf('zcat'),
  fn: zcatCommand,
})
