import type { PathSpec, RegisteredOp } from '@struktoai/mirage-core'
import { ResourceName } from '@struktoai/mirage-core'
import type { RedisAccessor } from '../../accessor/redis.ts'
import { truncate } from '../../core/redis/truncate.ts'

export const truncateOp: RegisteredOp = {
  name: 'truncate',
  resource: ResourceName.REDIS,
  filetype: null,
  write: true,
  fn: (accessor: RedisAccessor, path: PathSpec, args: readonly unknown[]) => {
    const length = args[0]
    if (typeof length !== 'number') {
      throw new TypeError('truncate op requires a number length as the first arg')
    }
    return truncate(accessor, path, length)
  },
}
